def isValidBST(root):
    prev = [float('-inf')]

    def inorder(node):
        if node is None:
            return True
        if not inorder(node.left):
            return False
        if prev[0] >= node.val:
            return False
        prev[0] = node.val
        return inorder(node.right)

    return inorder(root)

